    <section class="section toc">
      <h2>Table of Contents</h2>
      <ol>
        <li><a href="#executive-summary">Executive Summary</a></li>
        <li><a href="#image-sets">Image Sets Analyzed</a></li>
        <li><a href="#rag-set">RAG Database Images — Fantasy Icon Set</a></li>
        <li><a href="#beach-photo">Beach Photograph — _IMG3766.JPG</a></li>
        <li><a href="#cross-set-comparison">Cross-Set Comparison</a></li>
        <li><a href="#vision-patterns">Vision Model Performance Patterns</a></li>
        <li><a href="#findings">Key Findings and Recommendations</a></li>
